 cuisine cr\00E9ole\\n\\n\\n(ont un acc\00E8s PMR)","Descriptif du plan d''acc\00E8s":"","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"8/9/2025","Date de fermeture":"","Fournisseur - Nom":"Mme Patricia & Henri Beldan","Fournisseur - SIRET":"41800734000015","Fournisseur - adresse":"Mme Patricia & Henri Beldan: 6 Rue Victor Natvel, 97414 Entre-Deux","Fournisseur - contacts":"patou6505@hotmail.fr / 0692 64 39 64","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.250456, 55.469444","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
